import Navbar from '../shared/Navbar';
import Footer from '../shared/Footer';

export default function Home() {
  return (
    <div className="min-h-screen flex flex-col bg-white">
      <Navbar />
      <main className="flex-1">
        {/* Hero */}
        <section className="relative overflow-hidden">
          <div className="absolute inset-0 bg-gradient-to-br from-brand-50 to-white" />
          <div className="relative max-w-7xl mx-auto px-6 py-24">
            <div className="max-w-3xl">
              <h1 className="text-4xl md:text-6xl font-extrabold tracking-tight text-gray-900">
                Find your perfect workspace
              </h1>
              <p className="mt-5 text-lg text-gray-600">
                Discover and book coworking spaces tailored to your team’s needs—by location, amenities, and capacity.
              </p>
              <div className="mt-8 grid grid-cols-1 md:grid-cols-12 gap-3 bg-white/80 backdrop-blur rounded-xl p-3 shadow-card">
                <input className="md:col-span-5 h-12 px-4 rounded-lg border border-gray-200 focus:outline-none focus:ring-2 focus:ring-brand-400" placeholder="Location, city or area" />
                <input className="md:col-span-3 h-12 px-4 rounded-lg border border-gray-200 focus:outline-none focus:ring-2 focus:ring-brand-400" placeholder="Capacity" />
                <input className="md:col-span-2 h-12 px-4 rounded-lg border border-gray-200 focus:outline-none focus:ring-2 focus:ring-brand-400" placeholder="Budget" />
                <a href="/search" className="md:col-span-2 inline-flex items-center justify-center h-12 px-6 rounded-lg bg-brand-600 text-white font-semibold hover:bg-brand-700 transition">Search</a>
              </div>
            </div>
          </div>
        </section>

        {/* Features */}
        <section className="max-w-7xl mx-auto px-6 py-16">
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            {[
              {
                title: 'Personalized AI picks',
                desc: 'Smart recommendations based on your preferences and history.'
              },
              {
                title: 'Real-time availability',
                desc: 'Always know what’s open with live capacity tracking.'
              },
              {
                title: 'Seamless booking',
                desc: 'Secure payments and instant confirmation with agreements.'
              }
            ].map((f) => (
              <div key={f.title} className="p-6 rounded-2xl border border-gray-100 shadow-card">
                <h3 className="text-xl font-semibold text-gray-900">{f.title}</h3>
                <p className="mt-2 text-gray-600">{f.desc}</p>
              </div>
            ))}
          </div>
        </section>
      </main>
      <Footer />
    </div>
  );
}
